sql:
SELECT CH4_mean
FROM air_quality_data
WHERE record_id = 0;

SELECT site_id, AVG(PM25_mean) AS avg_pm2_5
FROM air_quality_data
GROUP BY site_id;

SELECT timestamp, site_id, CH4_mean
FROM air_quality_data
WHERE CH4_mean > (SELECT AVG(CH4_mean) FROM air_quality_data);

SELECT timestamp, CH4_mean
FROM air_quality_data
ORDER BY timestamp DESC;

SELECT COUNT(*) AS ch4_record_count
FROM air_quality_data
WHERE CH4_mean > (SELECT threshold FROM pollutants WHERE pollutant_name = 'Methane (CH4)');

SELECT MAX(CH4_mean) AS highest_CH4_mean
FROM air_quality_data
WHERE strftime('%Y', timestamp) = '2023';

external_knowledge:
- 'Significant health risks' refers to pollutants with a 'High' health impact rating;
- 'Safety levels' refers to the threshold values set for pollutants;
- 'Fairly reliable' data is defined as having a reliability score greater than 3 on a scale of 1 to 5.
